import{_ as a,o as t,c as r,ag as l}from"./chunks/framework.eQLvDOR_.js";const m=JSON.parse('{"title":"agent-modular-architecture","description":"","frontmatter":{"title":"agent-modular-architecture","concept":"智能体核心模块架构","concept_id":"agent-modular-architecture","aliases":["Hermes-Components","Agent-Toolchain"],"sources":["02_Library/AI_IDE_And_CLI/[AI_IDE_And_CLI] Hermes 全部高阶工具配置.md"],"related_concepts":["[[agent-harness-pattern]]","[[skill-lifecycle]]"],"created_at":"2026-04-21","last_compiled":"2026-04-21"},"headers":[],"relativePath":"wiki/concepts/agent-modular-architecture.md","filePath":"wiki/concepts/agent-modular-architecture.md","lastUpdated":null}'),i={name:"wiki/concepts/agent-modular-architecture.md"};function o(n,e,s,d,c,h){return t(),r("div",null,[...e[0]||(e[0]=[l('<h1 id="智能体核心模块架构-modular-agent-framework" tabindex="-1">智能体核心模块架构 (Modular Agent Framework) <a class="header-anchor" href="#智能体核心模块架构-modular-agent-framework" aria-label="Permalink to &quot;智能体核心模块架构 (Modular Agent Framework)&quot;">​</a></h1><h2 id="核心组件定义" tabindex="-1">核心组件定义 <a class="header-anchor" href="#核心组件定义" aria-label="Permalink to &quot;核心组件定义&quot;">​</a></h2><p>一个成熟的 2026 智能体（如 Hermes）不再是简单的 Prompt 包装，而是高度解耦的模块化系统。</p><h3 id="_1-身份层-identity-soul-md" tabindex="-1">1. 身份层 (Identity - SOUL.md) <a class="header-anchor" href="#_1-身份层-identity-soul-md" aria-label="Permalink to &quot;1. 身份层 (Identity - SOUL.md)&quot;">​</a></h3><ul><li>负责：定义人格、语气边界、核心任务设定。</li><li>进阶：动态迭代。模型根据对话反馈，自行更新其 SOUL 配置文件。</li></ul><h3 id="_2-记忆层-memory-hindsight" tabindex="-1">2. 记忆层 (Memory - Hindsight) <a class="header-anchor" href="#_2-记忆层-memory-hindsight" aria-label="Permalink to &quot;2. 记忆层 (Memory - Hindsight)&quot;">​</a></h3><ul><li>负责：跨 Session 的状态持久化。</li><li>关键特征：实体与关系提取。自动识别对话中的“任务截止日”、“偏好”等实体并建立图谱关联，而非简单的文本存储。</li></ul><h3 id="_3-感知层-perception-skills" tabindex="-1">3. 感知层 (Perception - Skills) <a class="header-anchor" href="#_3-感知层-perception-skills" aria-label="Permalink to &quot;3. 感知层 (Perception - Skills)&quot;">​</a></h3><ul><li><strong>抓取 &amp; 深度爬取</strong>：从单页抓取 (Jina Reader) 到结构化全域爬取 (Crawl4AI)。</li><li><strong>文档转化</strong>：Pandoc/Marker 实现全格式（PDF/DOCX/LaTeX）到 Markdown 的无损转化。</li><li><strong>环境操作</strong>：具备反爬能力的隐身浏览器控制。</li></ul><h3 id="_4-进化层-evolution" tabindex="-1">4. 进化层 (Evolution) <a class="header-anchor" href="#_4-进化层-evolution" aria-label="Permalink to &quot;4. 进化层 (Evolution)&quot;">​</a></h3><ul><li>负责：Prompt 与 Skill 的自我优化。</li><li>特性：基于遗传算法或反馈循环，自动优化其 Tools 的描述文本和调用逻辑。</li></ul><hr><h2 id="实践指南" tabindex="-1">实践指南 <a class="header-anchor" href="#实践指南" aria-label="Permalink to &quot;实践指南&quot;">​</a></h2><ul><li><strong>配置优先级</strong>：身份 (Soul) &gt; 感知 (Perception) &gt; 记忆 (Memory) &gt; 进化 (Evolution)。</li><li><strong>协同策略</strong>：使用 tokscale 等监控工具，分析各模块对 Token 消耗的贡献度，精准执行“分页（Paging）”。</li></ul><hr><h2 id="参考链接" tabindex="-1">参考链接 <a class="header-anchor" href="#参考链接" aria-label="Permalink to &quot;参考链接&quot;">​</a></h2><ul><li><a href="/s/webclips/library/AI_IDE_And_CLI/AI_IDE_And_CLI - Hermes 全部高阶工具配置.html">[AI_IDE_And_CLI] Hermes 全部高阶工具配置</a></li></ul>',17)])])}const _=a(i,[["render",o]]);export{m as __pageData,_ as default};
